import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting premiums", () => {
    it.todo("computes base premium for a single sword (plain item, new customer)");
    it.todo("computes base premium for a single amulet");
    it.todo("computes base premium for a single staff");
    it.todo("computes base premium for a single potion");
    it.todo("computes premium for a single rune component");
    it.todo("applies the special bundle price for 3 alike components");
    it.todo("applies a 50% surcharge for cursed items");
    it.todo("applies a 30% surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("applies a 20% loyalty discount for customers with >= 2 years");
    it.todo("applies a 15% repeat-contract discount on the second quote");
    it.todo("rounds the premium up to whole G in MHPCO's favor");
  });

  describe("Processing claims", () => {
    it.todo("reimburses 50% of damage minus deductible for items with enchantment >= 8");
    it.todo("reimburses 100% of damage minus deductible for items made of dragon material");
  });
});

